//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Field codes catalog, switches/formatting, and =formula evaluation".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-fidelity constraint
//! mined from ECMA-376 / ISO 29500-1 / MS-OI29500 for complex and simple
//! fields (`fldChar`/`instrText`/`fldSimple`), their formatting switches
//! (`\@`, `\#`, `\*`), and `=formula` fields.
//!
//! A FAILING assertion here is a REAL Word-compliance gap in stemma — NOT a
//! test to weaken to make pass. The assertion messages carry the rule text +
//! §refs so a failure is self-explanatory.
//!
//! Methodology (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim. `reserialize()` of an unedited document therefore reflects
//! stemma's verbatim-preservation contract. `xmlContains`/`xmlOmits`/regex
//! checks here target markup the serializer must faithfully reproduce
//! (instruction text, child ordering, structural fidelity) or schema validity.
//! Consumption semantics (what reads) are asserted on the READ side via
//! `read_accepted()`/`read_rejected()` (`to_text()` surfaces a field's cached
//! `result_text` as visible text — see `view.rs::opaque_visible_text`).

use std::io::{Cursor, Read as _, Write as _};

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx` whose `word/document.xml` body inner XML is
/// `body_xml` (wrapped in `<w:document …><w:body>…</w:body></w:document>`).
///
/// `extra_parts` are `(part_path, xml)` pairs (e.g. `("word/styles.xml", …)`);
/// each gets a `[Content_Types].xml` `<Override>` derived from a small known map.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = match *path {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content-type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse `bytes`, re-serialize via default export options, return its
/// `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// `read_accepted().to_text().trim()`.
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

/// `read_rejected().to_text().trim()`.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

/// Assert `validate(bytes)` reports no errors (opens-clean).
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = validate(bytes);
    assert!(
        report.ok,
        "{ctx} — expected opens-clean (no validation errors); issues={:?}",
        report.issues
    );
}

/// `xmlRegex` translation (no `regex` crate in dev-deps): split the pattern on
/// its ordered-wildcard tokens (`.*`, `[\s\S]*`, `[\s\S]*?`) and assert each
/// literal fragment appears in `hay`, in order, non-overlapping. Fragments that
/// still carry regex metacharacters must be pre-reduced by the caller to the
/// literal core stemma actually emits.
fn assert_ordered_contains(hay: &str, frags: &[&str], ctx: &str) {
    let mut from = 0usize;
    for frag in frags {
        match hay[from..].find(frag) {
            Some(rel) => from += rel + frag.len(),
            None => panic!(
                "{ctx} — expected ordered fragment {frag:?} (after offset {from}) not found\n--- XML ---\n{hay}"
            ),
        }
    }
}

