#[test]
fn formula_not_equal_operator_survives_escaped_and_cached_one_reads() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve">=3&lt;&gt;5</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>1</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("=3&lt;&gt;5"),
        "§17.16.3.3 (ECMA-376 / ISO 29500-1): '<>' is a defined not-equal operator; its '<' must reserialize XML-escaped (&lt;) verbatim inside instrText, not be unescaped or dropped — expected XML to contain =3&lt;&gt;5\n--- XML ---\n{xml}"
    );

    assert_eq!(
        accept_text(&b),
        "1",
        "§17.16.3.3: inequality operators yield 1 for true; the cached result run ('1') between separate and end is the displayed text — the engine must NOT recompute the comparison"
    );
    assert_eq!(
        reject_text(&b),
        "1",
        "§17.16.3.3: an untracked field reads identically on reject; the cached '1' is shown, never the instruction =3<>5"
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a balanced begin/separate/end complex field with escaped operators is schema-valid and must open without repair",
    );
}

#[test]
fn numeric_picture_three_subpictures_survive_verbatim() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve">=A1 \# "$#,##0.00;-$#,##0.00;$0"</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>$1,234.50</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("$#,##0.00;-$#,##0.00;$0"),
        "§17.16.4.2 (ECMA-376 / ISO 29500-1): the positive;negative;zero sub-pictures (with literal ';' separators) are ONE picture argument; every section and separator must reserialize verbatim, not be collapsed — expected XML to contain $#,##0.00;-$#,##0.00;$0\n--- XML ---\n{xml}"
    );

    assert_opens_clean(
        &b,
        "§17.16.4.2: a well-formed complex field with a multi-section numeric picture is schema-valid and opens without repair",
    );
}

#[test]
fn firstcap_general_switch_survives_and_cached_result_not_recased() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> AUTHOR \* FirstCap </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>mary smith</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "mary smith",
        "§17.16.4.3.2 / §17.16.4.3.3: the cached result run is the displayed text; the engine must NOT apply FirstCap casing to produce 'Mary smith' because field update timing is out of scope"
    );
    assert_eq!(
        reject_text(&b),
        "mary smith",
        "§17.16.4.3.2: an untracked field reads identically on reject; the cached result is shown verbatim, never re-cased and never the AUTHOR instruction"
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a balanced complex field with a general-format switch is schema-valid and opens without repair",
    );
}

#[test]
fn mergeformat_multi_run_result_structure_preserved() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> TIME \@ "HH:mm:ss" \* MERGEFORMAT </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>12:22:</w:t></w:r><w:r><w:rPr><w:u w:val="single"/></w:rPr><w:t>27</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    // xmlRegex: <w:t>12:22:</w:t>.*<w:rPr><w:u w:val="single"/></w:rPr><w:t>27</w:t>
    assert_ordered_contains(
        &xml,
        &[
            "<w:t>12:22:</w:t>",
            r#"<w:rPr><w:u w:val="single"/></w:rPr><w:t>27</w:t>"#,
        ],
        "§17.16.4.3.3 MERGEFORMAT: the run structure of the result is kept intact; the serializer must re-emit both result runs in order, preserving the underline rPr on the seconds run (regex translated to ordered-contains: no regex crate)",
    );

    assert!(
        xml.contains(r#"TIME \@ "HH:mm:ss" \* MERGEFORMAT"#),
        "§17.16.4.3.3 / §17.16.18 / §17.16.2: the full MERGEFORMAT instruction (with the quoted picture) must survive serialize verbatim so Word can re-read the field\n--- XML ---\n{xml}"
    );
}

#[test]
fn numeric_picture_section_separator_survives_verbatim() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> =1234.5 \# "$#,##0.00;-$#,##0.00" </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>$1,234.50</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("$#,##0.00;-$#,##0.00"),
        "§17.16.4.2: the ';' section separator is part of a single numeric switch-argument; the serializer must preserve the full picture incl. both positive/negative sections verbatim, never split on ';' — expected XML to contain $#,##0.00;-$#,##0.00\n--- XML ---\n{xml}"
    );

    assert_eq!(
        accept_text(&b),
        "$1,234.50",
        "§17.16.4.2 + field-result-preservation: the cached result run between separate and end is the displayed text; stemma evaluates no formula, so accept shows the cached '$1,234.50'"
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a balanced begin/separate/end complex field with a valid numeric picture is schema-valid; Word opens it without repair",
    );
}

#[test]
fn date_picture_no_whitespace_stays_unquoted() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> DATE \@ yyyy-MM-dd </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>2025-01-03</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"DATE \@ yyyy-MM-dd"#),
        "MS-OI29500 §2.1.458 / ISO §17.16.4.1: quotes are optional for a whitespace-free picture; the serializer must preserve the author's unquoted form verbatim, not re-quote it — expected XML to contain DATE \\@ yyyy-MM-dd\n--- XML ---\n{xml}"
    );
    assert!(
        !xml.contains(r#"\@ "yyyy-MM-dd""#),
        "MS-OI29500 §2.1.458: stemma must NOT add quotation marks around a whitespace-free switch-argument; Word never requires them and verbatim passthrough preserves the unquoted instruction — expected XML to OMIT \\@ \"yyyy-MM-dd\"\n--- XML ---\n{xml}"
    );

    assert_eq!(
        accept_text(&b),
        "2025-01-03",
        "§17.16.4.1: a DATE field's displayed result is the cached run; stemma does not recompute DATE, so accept shows the cached value"
    );
}

#[test]
fn charformat_complex_field_result_reads_instruction_hidden() {
    let body = r#"<w:p><w:r><w:t>Date: </w:t></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:rPr><w:b/></w:rPr><w:instrText xml:space="preserve"> DATE \* CHARFORMAT </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:rPr><w:b/></w:rPr><w:t>1/4/2006</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Date: 1/4/2006",
        "§17.16.4.3.3 / §17.16.18: CHARFORMAT only formats the result region; the displayed text is the leading run plus cached separate..end run '1/4/2006', and the DATE/CHARFORMAT instruction is never shown"
    );
    assert_eq!(
        reject_text(&b),
        "Date: 1/4/2006",
        "§17.16.4.3.3: the field is untracked, so reject is a no-op; the result region still reads identically and the field code stays hidden"
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a balanced begin/separate/end CHARFORMAT field is schema-valid; Word opens it without repair",
    );
}

#[test]
fn mergeformatinet_on_includepicture_survives_verbatim() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> INCLUDEPICTURE "http://example.com/logo.png" \* MERGEFORMATINET </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"\* MERGEFORMATINET"#),
        "MS-OI29500 §2.1.459 / ECMA-376 §17.16.5.27: MERGEFORMATINET is a Word extension absent from ISO; stemma must preserve the switch byte-verbatim, never strip an unrecognized field instruction — expected XML to contain \\* MERGEFORMATINET\n--- XML ---\n{xml}"
    );
    assert!(
        xml.contains("INCLUDEPICTURE"),
        "MS-OI29500 §2.1.459: the MERGEFORMATINET dimension-preserving semantics apply specifically to INCLUDEPICTURE; the field name must survive alongside the switch\n--- XML ---\n{xml}"
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a balanced begin/separate/end field carrying a Word-recognized switch is schema-valid; Word opens it without repair",
    );
}

#[test]
fn charformat_first_instrtext_run_rpr_survives() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:rPr><w:b/><w:color w:val="ED1C24"/><w:u w:val="single"/></w:rPr><w:instrText xml:space="preserve">D</w:instrText></w:r><w:r><w:instrText xml:space="preserve">ATE \* CHARFORMAT</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:rPr><w:b/><w:color w:val="ED1C24"/><w:u w:val="single"/></w:rPr><w:t>1/4/2006</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);

    // xmlRegex (rPr on the first instrText 'D' run):
    //   <w:rPr>(<w:b\s*/>|<w:b/>)[\s\S]*?<w:color w:val="ED1C24"/>[\s\S]*?<w:u w:val="single"/>[\s\S]*?</w:rPr>[\s\S]*?<w:instrText[^>]*>D</w:instrText>
    // Translated to ordered-contains; the (<w:b\s*/>|<w:b/>) alternation and
    // the <w:instrText[^>]*> char class are reduced to the literal cores stemma
    // emits (<w:b/> and …>D</w:instrText>).
    assert_ordered_contains(
        &xml,
        &[
            "<w:rPr>",
            "<w:b/>",
            r#"<w:color w:val="ED1C24"/>"#,
            r#"<w:u w:val="single"/>"#,
            "</w:rPr>",
            "D</w:instrText>",
        ],
        "§17.16.4.3.3 / §17.16.23: CHARFORMAT reuses the formatting of the run containing the first instrText after begin; that rPr (b/color/u) on the 'D' instrText run must survive serialize (regex translated to ordered-contains: alternation reduced to the <w:b/> literal stemma emits)",
    );

    assert!(
        xml.contains(r#"ATE \* CHARFORMAT"#),
        "§17.16.4.3.3: the CHARFORMAT switch is part of the field code split across instrText runs and must reserialize verbatim — expected XML to contain ATE \\* CHARFORMAT\n--- XML ---\n{xml}"
    );

    // xmlRegex: fldCharType="begin"[\s\S]*fldCharType="separate"[\s\S]*fldCharType="end"
    assert_ordered_contains(
        &xml,
        &[
            r#"fldCharType="begin""#,
            r#"fldCharType="separate""#,
            r#"fldCharType="end""#,
        ],
        "§17.16.18: complex-field boundary fldChars must reserialize in begin->separate->end document order (regex translated to ordered-contains)",
    );

    assert_opens_clean(
        &b,
        "§17.16.18: a well-formed CHARFORMAT complex field with formatted instrText runs is valid OOXML and must open without repair",
    );
}

#[test]
fn general_upper_switch_not_applied_to_cached_result_text() {
    let body = r#"<w:p><w:fldSimple w:instr="MERGEFIELD CompanyName \* Upper"><w:r><w:t>acme corp</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "acme corp",
        "§17.16.4.3.2 / §17.16.4.3.3 / §17.16.19: general-format switches apply only on a field update (timing out of scope); a non-updating engine surfaces the cached result run verbatim, so \\* Upper must NOT uppercase 'acme corp' on read"
    );
    assert_eq!(
        reject_text(&b),
        "acme corp",
        "§17.16.4.3.3: an untracked fldSimple reads identically on reject; the cached lowercase result is the displayed text, never an uppercased recomputation"
    );

    assert_opens_clean(
        &b,
        "§17.16.19: a MERGEFIELD fldSimple with a \\* Upper switch and a cached result is valid OOXML and opens without repair",
    );
}

